import{c as a,Q as e,j as i,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"Claude Code 最新功能实战：一个命令开 5 个 agent，24 小时自动跑到完成 — @yaohui12138","description":"","frontmatter":{"title":"Claude Code 最新功能实战：一个命令开 5 个 agent，24 小时自动跑到完成 — @yaohui12138","author":"超级个体｜柿子（@yaohui12138）","date":"2026-05-13T00:00:00.000Z","source":"https://x.com/yaohui12138/status/2054381772599931297","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-13-@yaohui12138-931297.md","filePath":"research/tweets/2026-05-13-@yaohui12138-931297.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-05-13-@yaohui12138-931297.md"};function l(r,t,n,d,h,g){return e(),i("div",null,[...t[0]||(t[0]=[o(`<h1 id="claude-code-最新功能实战-一个命令开-5-个-agent-24-小时自动跑到完成-—-yaohui12138" tabindex="-1">Claude Code 最新功能实战：一个命令开 5 个 agent，24 小时自动跑到完成 — @yaohui12138 <a class="header-anchor" href="#claude-code-最新功能实战-一个命令开-5-个-agent-24-小时自动跑到完成-—-yaohui12138" aria-label="Permalink to &quot;Claude Code 最新功能实战：一个命令开 5 个 agent，24 小时自动跑到完成 — @yaohui12138&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/yaohui12138/status/2054381772599931297" target="_blank" rel="noreferrer">https://x.com/yaohui12138/status/2054381772599931297</a><strong>作者</strong>：超级个体｜柿子（@yaohui12138） <strong>發布日期</strong>：2026-05-13 <strong>收錄日期</strong>：2026-05-13 <strong>類型</strong>：Twitter Article <strong>統計</strong>：38 likes · 13 retweets · 70 bookmarks · 5114 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>看完这篇文章让你对 claude code 的理解和使用技巧超过 99% 的人。</p><p>就在深夜，claude code 发布最新版本，支持了最新的功能 agent view 以及 /goal 命令。这绝对是 claude 历史上最伟大的更新，它彻底颠覆了人类在编程当中的定位，可以称为另一个&quot;cursor 时刻&quot;！</p><p>这已经不是&quot;AI 帮你写代码&quot;那个层面的事了。这是你终于可以像管理一个开发团队一样，管理多个 AI agent 同时干活。</p><h2 id="先说-agent-view-是什么" tabindex="-1">先说 Agent View 是什么？ <a class="header-anchor" href="#先说-agent-view-是什么" aria-label="Permalink to &quot;先说 Agent View 是什么？&quot;">​</a></h2><p>你在终端输入 <code>claude agents</code>，就打开了一个&quot;后台任务面板&quot;，所有你扔给 Claude Code 的后台任务，全在这一个屏幕里：</p><ul><li>哪些正在跑（working）</li><li>哪些在等你回复（awaiting input）</li><li>哪些已经完成（completed）</li></ul><p>关键是，每个 agent 都在独立的 git worktree 里工作。agent A 在 feature-auth 分支改登录模块，agent B 在 bugfix-api 分支修接口问题，agent C 在 refactor-ui 分支重构页面。它们互不干扰，不会因为改同一个文件打架。</p><p>你可以用快捷键快速切换、预览、回复任何一个 agent，不用开 10 个终端窗口，一个界面管理全部。</p><h2 id="再说-goal-命令-这个更牛了" tabindex="-1">再说 /goal 命令，这个更牛了 <a class="header-anchor" href="#再说-goal-命令-这个更牛了" aria-label="Permalink to &quot;再说 /goal 命令，这个更牛了&quot;">​</a></h2><p>以前你让 AI 干活，它干到一半经常停下来问你：&quot;接下来我该做什么？&quot;</p><p>/goal 命令就是给 agent 设定一个目标，让它自己跑到目标达成为止。比如你在会话里输入：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/goal 所有测试通过且 CI 变绿</span></span></code></pre></div><p>然后 Claude Code 会装一个 session 级的 Stop hook，在目标没达成之前，它不会停。它会自己修代码、跑测试、看报错、再改、再跑，一直到所有测试绿了为止。</p><p>这才是真正的&quot;自动化&quot;。不是&quot;帮你写 50% 的代码&quot;，是&quot;你定义目标，它负责跑通全流程&quot;。</p><h2 id="实战场景-一个人怎么用这套组合拳" tabindex="-1">实战场景：一个人怎么用这套组合拳 <a class="header-anchor" href="#实战场景-一个人怎么用这套组合拳" aria-label="Permalink to &quot;实战场景：一个人怎么用这套组合拳&quot;">​</a></h2><p>假设你现在要做一个重构项目，涉及 3 个模块：认证、API、前端 UI。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> refactor-auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;重构 src/auth/ 模块，改用新的 token 机制&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> refactor-api</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;重构 src/api/，统一错误处理&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> refactor-ui</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;重构 src/components/，应用新设计系统&quot;</span></span></code></pre></div><p>每个 agent 自动在独立的 worktree 和分支上工作。给每个 agent 设定目标：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/goal 所有单元测试通过，代码审查无警告</span></span></code></pre></div><p>关掉电脑，去健身 / 开会 / 睡觉。agent 会自己跑，遇到问题自己调试，直到目标达成。</p><p>回来后一键查看进度：<code>claude agents</code>，看到 3 个 agent 都是 completed 状态。</p><h2 id="快捷键速查-agent-view-功能" tabindex="-1">快捷键速查（agent view 功能） <a class="header-anchor" href="#快捷键速查-agent-view-功能" aria-label="Permalink to &quot;快捷键速查（agent view 功能）&quot;">​</a></h2><p>进入 Agent View 后：</p><ul><li>↑ / ↓ 选择会话</li><li>Space peek 预览 + 直接回复（不离开列表）</li><li>Enter 进入完整会话</li><li>Ctrl+T 置顶重要任务</li><li>Ctrl+S 按目录分组</li><li>Ctrl+X 连按两次 删除会话</li><li>? 显示所有快捷键</li></ul><p>把当前会话扔到后台：输入 <code>/bg</code>，清除目标：<code>/goal clear</code></p><h2 id="为什么说这是又一个-cursor-时刻" tabindex="-1">为什么说这是又一个 cursor 时刻 <a class="header-anchor" href="#为什么说这是又一个-cursor-时刻" aria-label="Permalink to &quot;为什么说这是又一个 cursor 时刻&quot;">​</a></h2><p>因为过去 cursor 带给我们用 AI 的心智模型是：AI 是工具，我是使用者。但 Agent View + /goal 把这个关系改成了：AI 是团队成员，我是 PM。</p><p>你不用教它每一步怎么做，你只需要：</p><ul><li>拆解任务（这个本来就是自己的活）</li><li>分配给不同 agent（每个 agent 有独立上下文和目标）</li><li>定期 check 进度，必要时介入调整</li></ul><p>Anthropic 自己内部现在大部分代码已经是 Claude Code 写的，工程师的工作重心变成了产品思维 + agent 编排。</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude Code 新功能 Agent View + /goal 實現並行多 Agent 管理，人類角色從寫碼轉為 PM</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>Agent View</strong>：<code>claude agents</code> 指令開啟統一後台面板，管理多個並行執行的 agent</li><li><strong>git worktree 隔離</strong>：每個 agent 在獨立分支工作，避免文件衝突</li><li><strong>/goal 命令</strong>：設定目標後 agent 自主執行直到達成，安裝 session 級 Stop hook</li><li><strong>角色轉換</strong>：開發者從執行者 → PM，負責拆解任務、分配、驗收</li><li><strong><code>--bg -w</code> 旗標</strong>：背景啟動 + 指定 worktree，一次開多個 agent</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>指令：<code>claude agents</code>、<code>claude --bg -w &lt;branch&gt; &quot;&lt;task&gt;&quot;</code>、<code>/goal &lt;condition&gt;</code>、<code>/bg</code>、<code>/goal clear</code></li><li>快捷鍵：Space（預覽回覆）、Ctrl+T（置頂）、Ctrl+S（分組）、Ctrl+X×2（刪除）</li><li>架構：git worktree 分支隔離 + session Stop hook</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>過度誇張「最偉大更新」</strong>：功能有實際價值，但 clickbait 語氣降低了可信度；需自行測試驗證</li><li><strong>「自主跑到完成」有邊界</strong>：/goal 依賴 Stop hook，若任務無法被測試驗收（如「寫一篇文章」），效果有限</li><li><strong>worktree 合並責任未提</strong>：多個 agent 各自完成後的 PR review 和 merge 衝突處理留給使用者，非全自動</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>具體指令和快捷鍵可立即應用於 Claude Code 工作流</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>Agent View + /goal 是新功能，組合使用視角有價值</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>作者實測報告，但缺乏對照組和失敗案例</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>說明了 worktree 隔離和 Stop hook 機制，但未觸及限制條件</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>適用所有 Claude Code 使用者，特別是多任務並行場景</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.8/10</strong></td><td>8×0.3+7×0.2+5×0.2+6×0.15+7×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：新功能操作指南，核心是可直接套用的 agent 管理工作流和指令清單</p>`,47)])])}const u=a(s,[["render",l]]);export{c as __pageData,u as default};
